    {"id": "ex-mod9-10", "type": "code-correction", "question": "Erreur SSA", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "%1 = add i32 %a, 5\n%1 = mul i32 %1, 2", "correctCode": "%1 = add i32 %a, 5\n%2 = mul i32 %1, 2", "hints": ["En SSA, une variable (%1) ne peut être assignée qu'UNE FOIS."], "explanation": "C'est la règle d'or de l'IR LLVM : créer une nouvelle version de variable à chaque modification."}}
