# --- MODULE 10 : Le Middle-End (Optimisations IR) ---
exercises.extend([
    {"id": "ex-mod10-1", "type": "quiz", "question": "Que fait l'optimisation 'Constant Folding' (Pliage de Constantes) ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Elle calcule les expressions mathématiques simples à la compilation (ex: 5 * 2 + 10 -> 20) pour que le CPU n'ait pas à le faire."}, {"id": "b", "text": "Elle chiffre les constantes."}, {"id": "c", "text": "Elle réduit la taille de l'écran."}], "correctId": "a", "explanation": "Le compilateur fait les maths à votre place."}},
    {"id": "ex-mod10-2", "type": "quiz", "question": "Que fait l'optimisation 'Dead Code Elimination' (DCE) ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Elle supprime le code injoignable (après un return) ou les calculs dont le résultat n'est jamais utilisé/retourné."}, {"id": "b", "text": "Elle ferme le programme."}, {"id": "c", "text": "Elle efface les commentaires."}], "correctId": "a", "explanation": "C'est ce qui fait que des boucles énormes vides sont transformées en RIEN par -O3."}},
    {"id": "ex-mod10-3", "type": "quiz", "question": "Qu'est-ce que l'optimisation 'Loop Unrolling' (Déroulage de boucle) ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Répéter le corps de la boucle plusieurs fois en dur pour réduire le nombre total de comparaisons/sauts (overhead)."}, {"id": "b", "text": "Transformer une boucle en appel de fonction."}, {"id": "c", "text": "Mettre la boucle à l'envers."}], "correctId": "a", "explanation": "Le fichier binaire grossit (plus d'instructions), mais le CPU tourne beaucoup plus vite."}},
    {"id": "ex-mod10-4", "type": "fill-blank", "question": "Constant Propagation", "difficulty": "medium", "xpReward": 35, "data": {"codeTemplate": "; Avant : \n; int x = 10; \n; return x * 2;\n\n; Après Constant Propagation & Folding (Middle-end) :\nreturn __BLANK__;", "blanks": [{"id": "1", "answer": "20", "hint": "Le résultat final compilé."}], "explanation": "La variable x est traquée, sa constante propagée, puis pliée (Folding)."}},
    {"id": "ex-mod10-5", "type": "quiz", "question": "Qu'est-ce que l'Inline Expansion (Inlining) de fonction ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Remplacer l'appel à une fonction (call) par le code entier de la fonction, évitant le coût d'une Frame."}, {"id": "b", "text": "Mettre le texte en ligne."}, {"id": "c", "text": "Changer le type de retour."}], "correctId": "a", "explanation": "C'est l'optimisation la plus importante du C++ (qui justifie le Zero-Overhead des getters/setters)."}},
    {"id": "ex-mod10-6", "type": "quiz", "question": "Pourquoi l'optimisation 'LICM' (Loop Invariant Code Motion) est-elle cruciale ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Elle sort les calculs qui ne changent pas (invariants) en dehors de la boucle pour ne pas les refaire à chaque itération."}, {"id": "b", "text": "Elle inverse les boucles."}, {"id": "c", "text": "Elle supprime la boucle."}], "correctId": "a", "explanation": "Exemple: si vous faites `a = x * 2` dans un `for(i=0...100)`, le compilateur mettra `a = x * 2` avant le `for`."}},
    {"id": "ex-mod10-7", "type": "drag-drop", "question": "La cascade des Optimisations LLVM", "difficulty": "hard", "xpReward": 50, "data": {"items": [{"id": "1", "text": "Inlining (Ramène le code des petites fonctions à l'intérieur)"}, {"id": "2", "text": "Constant Propagation & Folding (Résout les maths statiques exposées par l'inlining)"}, {"id": "3", "text": "Dead Code Elimination (Supprime les conditions If(false) résolues au-dessus)"}, {"id": "4", "text": "Vectorization (Transforme les boucles épurées restantes en SIMD)"}], "correctOrder": ["1", "2", "3", "4"], "instruction": "Les 'Passes' d'optimisation se nourrissent les unes des autres. Rangez-les logiquement.", "explanation": "Cette synergie (Passes) fait toute la magie d'un bon compilateur (-O3)."}},
    {"id": "ex-mod10-8", "type": "fill-blank", "question": "Common Subexpression Elimination (CSE)", "difficulty": "hard", "xpReward": 50, "data": {"codeTemplate": "; CSE : Si le compilateur voit 'y = a * b' puis 'z = a * b' plus loin,\n; Il supprime le 2ème calcul et fait simplement : \nz = __BLANK__", "blanks": [{"id": "1", "answer": "y", "hint": "Il réutilise le résultat précédent."}], "explanation": "L'IR stocke le graphe des valeurs. Si un nœud a la même entrée, il fusionne les nœuds (GPN)."}},
    {"id": "ex-mod10-9", "type": "quiz", "question": "En quoi consiste la vectorisation automatique (Auto-Vectorization) du Middle-End ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Il détecte une boucle traitant un tableau séquentiel et la remplace par des blocs d'opérations SIMD (ex: vaddps)."}, {"id": "b", "text": "Il crée des vecteurs C++ dynamiquement."}, {"id": "c", "text": "Il dessine des vecteurs."}], "correctId": "a", "explanation": "C'est le Graal de l'optimisation moderne, rendant le code jusqu'à 16x plus rapide sans changer une ligne de C."}},
    {"id": "ex-mod10-10", "type": "code-correction", "question": "Aliasing Pointers", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "void add(int* a, int* b) {\n  for(int i=0; i<100; i++) {\n    *a += *b;\n  }\n}", "correctCode": "void add(int* restrict a, int* restrict b) {\n  // Sans 'restrict', le compilateur craint que 'a' et 'b' pointent \n  // vers la même adresse mémoire (Aliasing) et n'optimisera pas.\n}", "hints": ["Mot-clé magique C99 pour promettre qu'il n'y a pas d'aliasing."], "explanation": "Si `a == b`, chaque `*a += *b` modifie la cible de `b`. Le compilateur ne peut donc pas mettre `*b` en cache registre (ou vectoriser). `restrict` résout ce problème."}}
])

# --- MODULE 11 : Le Backend (Génération ASM) ---
exercises.extend([
    {"id": "ex-mod11-1", "type": "quiz", "question": "Quelle est la tâche principale du Backend LLVM/GCC ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Traduire l'IR abstraite optimisée en un véritable code Assembleur (x86, ARM, RISC-V) propre au processeur cible."}, {"id": "b", "text": "Compiler le code en Python."}, {"id": "c", "text": "Créer le fichier source C."}], "correctId": "a", "explanation": "Le Backend se charge de la réalité physique (Registres limités, architecture matérielle)."}},
    {"id": "ex-mod11-2", "type": "quiz", "question": "Comment s'appelle le processus d'assigner l'infinité de variables de l'IR (%1, %2...) aux 16 registres réels de x86-64 ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Register Allocation (Allocation de registres)."}, {"id": "b", "text": "Variable Sorting."}, {"id": "c", "text": "Garbage Collection."}], "correctId": "a", "explanation": "C'est l'un des algorithmes les plus complexes de l'informatique (coloration de graphes)."}},
    {"id": "ex-mod11-3", "type": "quiz", "question": "Que se passe-t-il lors de l'Allocation de Registres s'il y a plus de 'Variables Vivantes' que de registres physiques ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Le Backend effectue un 'Register Spilling' : il 'déverse' l'excédent sur la pile (RAM) (très lent)."}, {"id": "b", "text": "Il crashe."}, {"id": "c", "text": "Il supprime les variables."}], "correctId": "a", "explanation": "C'est pourquoi écrire des fonctions gigantesques avec 100 variables locales détruit les performances."}},
    {"id": "ex-mod11-4", "type": "fill-blank", "question": "Instruction Selection", "difficulty": "medium", "xpReward": 35, "data": {"codeTemplate": "; Le Backend utilise la 'Sélection d'Instruction'.\n; Par exemple, traduire `%3 = mul i32 %1, 8` vers :\n__BLANK__ eax, 3", "blanks": [{"id": "1", "answer": "shl", "hint": "Instruction spécifique x86 (Shift Left) au lieu de mul."}], "explanation": "Le Backend connaît les astuces intimes de l'architecture cible pour produire le code le plus rapide."}},
    {"id": "ex-mod11-5", "type": "quiz", "question": "Qu'est-ce que le 'Peephole Optimization' (Optimisation par le trou de serrure) ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Une passe finale du Backend qui regarde 2-3 instructions assembleur générées et les remplace par un motif plus court (ex: 'mov eax, 0' devient 'xor eax, eax')."}, {"id": "b", "text": "Regarder le code source de loin."}, {"id": "c", "text": "Cacher le code binaire."}], "correctId": "a", "explanation": "C'est un nettoyage microscopique de toute dernière minute sur le texte Assembleur final."}},
    {"id": "ex-mod11-6", "type": "quiz", "question": "Quel algorithme est couramment utilisé pour l'Allocation de Registres optimale ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "La Coloration de Graphe (Graph Coloring)."}, {"id": "b", "text": "Le Tri à Bulles."}, {"id": "c", "text": "A-Star."}], "correctId": "a", "explanation": "Si 2 variables sont 'vivantes' en même temps, elles sont reliées. On tente de colorier le graphe entier avec K couleurs (les K registres CPU)."}},
    {"id": "ex-mod11-7", "type": "drag-drop", "question": "Workflow complet du Backend", "difficulty": "hard", "xpReward": 50, "data": {"items": [{"id": "1", "text": "Instruction Selection (Choix des Opcodes CPU cibles, ex: x86)"}, {"id": "2", "text": "Instruction Scheduling (Réordonner pour éviter les pipeline stalls CPU)"}, {"id": "3", "text": "Register Allocation (Coloration de Graphes et Spilling)"}, {"id": "4", "text": "Peephole Opt / Code Emission (Génération des bits finaux / Fichier Objet .o)"}], "correctOrder": ["1", "2", "3", "4"], "instruction": "Rangez les 4 étapes vitales du travail du Backend LLVM/GCC.", "explanation": "L'ordre d'exécution détermine grandement la vitesse du binaire (ex: l'allocation dépend de l'ordre schedulé)."}},
    {"id": "ex-mod11-8", "type": "fill-blank", "question": "Liveness Analysis (Analyse de vivacité)", "difficulty": "hard", "xpReward": 50, "data": {"codeTemplate": "; L'analyse de 'Liveness' détermine à quel moment une variable peut être écrasée par une autre pour recycler son registre.\n; Une variable est 'vivante' depuis sa déclaration jusqu'à sa dernière __BLANK__.", "blanks": [{"id": "1", "answer": "utilisation", "hint": "Lecture (Use)."}], "explanation": "Dès qu'une variable n'est plus lue plus bas dans le code, son registre physique est libre pour quelqu'un d'autre."}},
    {"id": "ex-mod11-9", "type": "quiz", "question": "Qu'est-ce que le 'Link Time Optimization' (LTO) ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Une technique où le compilateur génère non pas de l'assembleur pur, mais un fichier binaire hybride IR/Objet, permettant au Linker final (qui a la vue sur TOUS les fichiers .o du projet) d'Inliner massivement entre différents fichiers C++."}, {"id": "b", "text": "Le fait de supprimer les liens externes."}, {"id": "c", "text": "Optimiser le téléchargement d'un lien."}], "correctId": "a", "explanation": "Sans LTO, l'optimisation s'arrête aux frontières du fichier.h/.cpp. Avec LTO, la vue globale permet un gain drastique de vitesse."}},
    {"id": "ex-mod11-10", "type": "code-correction", "question": "Linker Error classique", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "// Fichier A.cpp\nextern int globale;\nint main() { return globale; }", "correctCode": "// Fichier A.cpp\nextern int globale;\nint main() { return globale; }\n\n// Dans un autre fichier (B.cpp)\nint globale = 42;", "hints": ["L'erreur de linker 'Undefined reference' survient quand un symbole extern n'existe nulle part physiquement."], "explanation": "Le Backend a produit A.o sans erreur. C'est le Linker (Éditeur de liens) qui plante car il ne trouve pas l'adresse physique de la variable globale 'globale' dans les autres fichiers Objets."}}
])

